import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ViewType {
  DASHBOARD = 'DASHBOARD',
  DICTIONARY = 'DICTIONARY',
  FLASHCARDS = 'FLASHCARDS',
  SPEAKING = 'SPEAKING',
  BATTLE = 'BATTLE',
  PET = 'PET'
}

export interface UserStats {
  coins: number;
  streak: number;
  level: 'Gà Mờ' | 'Dân Chơi' | 'Trùm Cuối';
  xp: number;
}

export interface WordDefinition {
  word: string;
  phonetic: string;
  definition: string;
  slangMeaning: string;
  example: string;
  vietnameseMeaning: string;
}

export interface Flashcard {
  id: string;
  term: string;
  definition: string;
  imageUrl: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSmartDefinition = async (word: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Giải thích từ vựng tiếng Anh "${word}" theo phong cách Gen Z Việt Nam cực chill. Bao gồm nghĩa chuẩn, nghĩa bóng/slang, và một ví dụ hài hước hoặc đang viral.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          word: { type: Type.STRING },
          phonetic: { type: Type.STRING },
          vietnameseMeaning: { type: Type.STRING },
          definition: { type: Type.STRING },
          slangMeaning: { type: Type.STRING },
          example: { type: Type.STRING }
        },
        required: ["word", "phonetic", "vietnameseMeaning", "definition", "slangMeaning", "example"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getSpeakingFeedback = async (sentence: string, userTranscript: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Bạn là Tùng Bot, một giáo viên tiếng Anh cực cool. 
    Câu mẫu: "${sentence}"
    Người học đọc: "${userTranscript}"
    Hãy nhận xét ngắn gọn, hài hước bằng tiếng Việt về phát âm, chỉ ra lỗi sai và chấm điểm trên thang 100.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          feedback: { type: Type.STRING },
          tips: { type: Type.STRING }
        },
        required: ["score", "feedback", "tips"]
      }
    }
  });
  return JSON.parse(response.text);
};

export const getQuizQuestions = async (level: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Tạo 5 câu hỏi trắc nghiệm tiếng Anh trình độ ${level} cho người Việt, phong cách hài hước.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            answer: { type: Type.STRING },
            explanation: { type: Type.STRING }
          },
          required: ["question", "options", "answer", "explanation"]
        }
      }
    }
  });
  return JSON.parse(response.text);
};

import React, { useState, useEffect } from 'react';
import { ViewType, UserStats } from './types';
import Dashboard from './components/Dashboard';
import Dictionary from './components/Dictionary';
import Flashcards from './components/Flashcards';
import SpeakingCoach from './components/SpeakingCoach';
import BattleArena from './components/BattleArena';
import PetStore from './components/PetStore';
import { 
  Home, 
  Book, 
  Layers, 
  Mic2, 
  Swords, 
  Ghost, 
  Coins, 
  Flame,
  Menu,
  X
} from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>(ViewType.DASHBOARD);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [stats, setStats] = useState<UserStats>({
    coins: 1250,
    streak: 7,
    level: 'Dân Chơi',
    xp: 450
  });

  const addCoins = (amount: number) => {
    setStats(prev => ({ ...prev, coins: prev.coins + amount }));
  };

  const renderView = () => {
    switch (currentView) {
      case ViewType.DASHBOARD: return <Dashboard stats={stats} setView={setCurrentView} />;
      case ViewType.DICTIONARY: return <Dictionary addCoins={addCoins} />;
      case ViewType.FLASHCARDS: return <Flashcards addCoins={addCoins} />;
      case ViewType.SPEAKING: return <SpeakingCoach addCoins={addCoins} />;
      case ViewType.BATTLE: return <BattleArena addCoins={addCoins} stats={stats} />;
      case ViewType.PET: return <PetStore stats={stats} setStats={setStats} />;
      default: return <Dashboard stats={stats} setView={setCurrentView} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <header className="md:hidden flex items-center justify-between p-4 skibidi-glass sticky top-0 z-50">
        <h1 className="text-2xl font-extrabold tracking-tighter text-orange-500">TÙNG SKIBIDI</h1>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2">
          {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {/* Sidebar Navigation */}
      <nav className={`
        fixed inset-0 z-40 bg-slate-900 md:bg-transparent md:relative md:flex md:flex-col md:w-64 lg:w-72
        transform transition-transform duration-300 ease-in-out
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="flex flex-col h-full p-6 skibidi-glass m-4 rounded-3xl border-slate-800">
          <div className="hidden md:block mb-8">
            <h1 className="text-3xl font-extrabold tracking-tighter text-orange-500">TÙNG SKIBIDI</h1>
            <p className="text-slate-400 text-xs mt-1 font-semibold uppercase tracking-widest">Học Chuẩn Trend</p>
          </div>

          <div className="flex flex-col gap-2 flex-grow">
            <NavItem icon={<Home />} label="Trang chủ" active={currentView === ViewType.DASHBOARD} onClick={() => {setCurrentView(ViewType.DASHBOARD); setIsMenuOpen(false);}} />
            <NavItem icon={<Book />} label="Từ điển xịn" active={currentView === ViewType.DICTIONARY} onClick={() => {setCurrentView(ViewType.DICTIONARY); setIsMenuOpen(false);}} />
            <NavItem icon={<Layers />} label="Thẻ ghi nhớ" active={currentView === ViewType.FLASHCARDS} onClick={() => {setCurrentView(ViewType.FLASHCARDS); setIsMenuOpen(false);}} />
            <NavItem icon={<Mic2 />} label="Luyện nói AI" active={currentView === ViewType.SPEAKING} onClick={() => {setCurrentView(ViewType.SPEAKING); setIsMenuOpen(false);}} />
            <NavItem icon={<Swords />} label="Đấu trường" active={currentView === ViewType.BATTLE} onClick={() => {setCurrentView(ViewType.BATTLE); setIsMenuOpen(false);}} />
            <NavItem icon={<Ghost />} label="Nuôi thú" active={currentView === ViewType.PET} onClick={() => {setCurrentView(ViewType.PET); setIsMenuOpen(false);}} />
          </div>

          <div className="mt-auto space-y-4 pt-6 border-t border-slate-800">
            <div className="flex items-center gap-3 px-4">
              <div className="p-2 rounded-xl bg-orange-500/20 text-orange-500">
                <Flame size={20} />
              </div>
              <div>
                <p className="text-xs text-slate-400">Chuỗi ngày</p>
                <p className="font-bold">{stats.streak} ngày</p>
              </div>
            </div>
            <div className="flex items-center gap-3 px-4">
              <div className="p-2 rounded-xl bg-yellow-500/20 text-yellow-500">
                <Coins size={20} />
              </div>
              <div>
                <p className="text-xs text-slate-400">Skibidi Coins</p>
                <p className="font-bold">{stats.coins.toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow p-4 md:p-8 overflow-y-auto">
        <div className="max-w-5xl mx-auto pb-20 md:pb-0">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`
      flex items-center gap-4 px-4 py-3 rounded-2xl transition-all duration-200
      ${active 
        ? 'skibidi-gradient text-white shadow-lg shadow-orange-500/20' 
        : 'hover:bg-slate-800 text-slate-400 hover:text-white'}
    `}
  >
    {React.cloneElement(icon as React.ReactElement, { size: 22 })}
    <span className="font-bold">{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { Search, Loader2, Sparkles, Volume2, MessageSquareText } from 'lucide-react';
import { getSmartDefinition } from '../services/geminiService';
import { WordDefinition } from '../types';

interface DictionaryProps {
  addCoins: (amount: number) => void;
}

const Dictionary: React.FC<DictionaryProps> = ({ addCoins }) => {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState<WordDefinition | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await getSmartDefinition(query);
      setResult(data);
      addCoins(10); // Reward for searching
    } catch (err) {
      setError('Úi, Tùng Bot chưa tìm thấy từ này. Thử từ khác xem sao!');
    } finally {
      setLoading(false);
    }
  };

  const playAudio = () => {
    const utterance = new SpeechSynthesisUtterance(result?.word);
    utterance.lang = 'en-US';
    window.speechSynthesis.speak(utterance);
  };

  return (
    <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom duration-500">
      <div className="mb-12 text-center">
        <h2 className="text-4xl font-black mb-4">Từ điển "Giao Quẻ" 🔮</h2>
        <p className="text-slate-400">Tra từ kiểu mới, học vèo vèo không mỏi mắt.</p>
      </div>

      <form onSubmit={handleSearch} className="relative group mb-8">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Nhập từ muốn tra (ví dụ: Riz, Ghosting...)"
          className="w-full bg-slate-900 border-2 border-slate-800 rounded-2xl py-5 px-14 text-xl font-bold focus:border-orange-500 outline-none transition-all"
        />
        <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-orange-500 transition-colors" />
        <button
          type="submit"
          disabled={loading}
          className="absolute right-3 top-1/2 -translate-y-1/2 px-6 py-2 bg-orange-500 rounded-xl font-bold hover:bg-orange-600 disabled:opacity-50 flex items-center gap-2"
        >
          {loading ? <Loader2 className="animate-spin" /> : 'Tra ngay'}
        </button>
      </form>

      {error && (
        <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-500 rounded-2xl text-center mb-8">
          {error}
        </div>
      )}

      {result && !loading && (
        <div className="space-y-6 animate-in zoom-in-95 duration-300">
          <div className="skibidi-glass p-8 rounded-3xl border-orange-500/30">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h3 className="text-5xl font-black text-orange-500 mb-2 uppercase tracking-tighter">{result.word}</h3>
                <p className="text-slate-400 font-mono text-lg">{result.phonetic}</p>
              </div>
              <button 
                onClick={playAudio}
                className="w-16 h-16 rounded-full bg-slate-800 hover:bg-slate-700 flex items-center justify-center text-orange-500 transition-all border border-slate-700"
              >
                <Volume2 size={32} />
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-8">
              <div className="p-5 rounded-2xl bg-slate-800/50 border border-slate-700">
                <p className="text-xs font-bold text-orange-400 uppercase tracking-widest mb-2">Nghĩa tiếng Việt</p>
                <p className="text-xl font-bold">{result.vietnameseMeaning}</p>
              </div>
              <div className="p-5 rounded-2xl bg-purple-500/10 border border-purple-500/20">
                <div className="flex items-center gap-2 mb-2">
                  <Sparkles size={16} className="text-purple-400" />
                  <p className="text-xs font-bold text-purple-400 uppercase tracking-widest">Góc Gen Z</p>
                </div>
                <p className="text-xl font-bold italic">"{result.slangMeaning}"</p>
              </div>
            </div>

            <div className="mt-8 p-6 rounded-2xl bg-slate-900/80 border border-slate-800">
              <div className="flex items-start gap-4">
                <MessageSquareText className="text-orange-500 shrink-0 mt-1" />
                <div>
                  <p className="text-sm font-semibold text-slate-500 mb-2 uppercase tracking-widest">Ví dụ thực tế</p>
                  <p className="text-lg leading-relaxed text-slate-200">{result.example}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {!result && !loading && !error && (
        <div className="text-center py-20 opacity-30 select-none">
          <Book size={100} className="mx-auto mb-4" />
          <p className="text-xl font-bold">Thử một từ để thấy điều kỳ diệu!</p>
        </div>
      )}
    </div>
  );
};

export default Dictionary;

import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Play, RefreshCw, Trophy, MessageCircle, ArrowRight } from 'lucide-react';
import { getSpeakingFeedback } from '../services/geminiService';

interface SpeakingCoachProps {
  addCoins: (amount: number) => void;
}

const SpeakingCoach: React.FC<SpeakingCoachProps> = ({ addCoins }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState<any>(null);
  const [currentSentence, setCurrentSentence] = useState("I think learning English with Tung Skibidi is so much fun!");

  const sentences = [
    "I think learning English with Tung Skibidi is so much fun!",
    "No cap, this app is the goat for learning slang.",
    "Can you give me a hand with this task?",
    "That movie was absolute fire, you should check it out."
  ];

  const toggleRecording = () => {
    if (!isRecording) {
      setIsRecording(true);
      setTranscript('');
      // In a real app, we'd use the Web Speech API or stream audio to Gemini
      // Here we simulate transcription
      setTimeout(() => {
        setTranscript(currentSentence.replace("fun", "fan")); // Simulate a small error
        setIsRecording(false);
      }, 3000);
    }
  };

  useEffect(() => {
    if (transcript && !isRecording) {
      handleEvaluate();
    }
  }, [transcript]);

  const handleEvaluate = async () => {
    setLoading(true);
    try {
      const result = await getSpeakingFeedback(currentSentence, transcript);
      setFeedback(result);
      if (result.score > 80) addCoins(50);
      else addCoins(10);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const nextSentence = () => {
    const next = sentences[Math.floor(Math.random() * sentences.length)];
    setCurrentSentence(next);
    setFeedback(null);
    setTranscript('');
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in fade-in slide-in-from-right duration-500">
      <div className="text-center">
        <h2 className="text-4xl font-black mb-4">Luyện Phát Âm "Dân Chơi" 🎙️</h2>
        <p className="text-slate-400">Nói chuẩn, nói hay, nói không bị quê cùng AI.</p>
      </div>

      <div className="skibidi-glass p-8 rounded-3xl border-slate-800 space-y-6">
        <div className="p-6 rounded-2xl bg-slate-900 border border-slate-800 text-center">
          <p className="text-xs font-bold text-slate-500 mb-4 uppercase tracking-widest">Đọc câu này nè:</p>
          <h3 className="text-2xl md:text-3xl font-bold text-slate-100">{currentSentence}</h3>
        </div>

        <div className="flex flex-col items-center justify-center py-10">
          <button
            onClick={toggleRecording}
            disabled={loading}
            className={`
              w-24 h-24 rounded-full flex items-center justify-center transition-all duration-300
              ${isRecording 
                ? 'bg-red-500 animate-pulse shadow-2xl shadow-red-500/50 scale-110' 
                : 'bg-purple-600 hover:bg-purple-500 shadow-xl shadow-purple-500/30'}
              disabled:opacity-50
            `}
          >
            {isRecording ? <MicOff size={40} className="text-white" /> : <Mic size={40} className="text-white" />}
          </button>
          <p className="mt-6 font-bold text-lg">
            {isRecording ? 'Đang lắng nghe...' : 'Nhấn để bắt đầu nói'}
          </p>
        </div>

        {loading && (
          <div className="flex items-center justify-center gap-2 py-4 text-purple-400">
            <RefreshCw className="animate-spin" />
            <span className="font-bold">Tùng Bot đang chấm điểm...</span>
          </div>
        )}

        {feedback && !loading && (
          <div className="animate-in zoom-in-95 duration-300 space-y-4">
            <div className="flex items-center gap-6 p-6 rounded-2xl bg-slate-800/50 border border-slate-700">
              <div className="w-20 h-20 rounded-2xl skibidi-gradient flex flex-col items-center justify-center text-white shrink-0">
                <Trophy size={28} />
                <span className="text-2xl font-black">{feedback.score}</span>
              </div>
              <div>
                <p className="text-slate-400 text-sm font-semibold mb-1 uppercase tracking-widest">Tùng Bot nhận xét:</p>
                <p className="text-xl font-bold leading-tight">{feedback.feedback}</p>
              </div>
            </div>

            <div className="p-6 rounded-2xl bg-blue-500/10 border border-blue-500/20 flex gap-4">
              <MessageCircle className="text-blue-400 shrink-0" />
              <div>
                <p className="text-xs font-bold text-blue-400 mb-1 uppercase tracking-widest">Tip cho bạn</p>
                <p className="text-slate-300">{feedback.tips}</p>
              </div>
            </div>

            <button 
              onClick={nextSentence}
              className="w-full py-4 rounded-2xl bg-slate-800 hover:bg-slate-700 font-bold transition-all flex items-center justify-center gap-2"
            >
              Thử câu tiếp theo <ArrowRight size={20} />
            </button>
          </div>
        )}
      </div>

      <div className="p-6 bg-slate-900 border border-slate-800 rounded-3xl opacity-60">
        <h4 className="text-sm font-bold text-slate-500 mb-2">HƯỚNG DẪN:</h4>
        <ul className="text-xs space-y-1 text-slate-400 list-disc list-inside">
          <li>Hãy nói to, rõ ràng ở nơi yên tĩnh.</li>
          <li>Đừng lo lắng về lỗi sai, Tùng Bot rất dễ tính!</li>
          <li>Điểm trên 80 sẽ nhận được x5 coins.</li>
        </ul>
      </div>
    </div>
  );
};

export default SpeakingCoach;

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, RotateCw, CheckCircle2, XCircle } from 'lucide-react';
import { Flashcard } from '../types';

interface FlashcardsProps {
  addCoins: (amount: number) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ addCoins }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [completed, setCompleted] = useState(false);

  const cards: Flashcard[] = [
    { 
      id: '1', 
      term: 'No Cap', 
      definition: 'Thật luôn, không hề điêu, thề danh dự!', 
      imageUrl: 'https://picsum.photos/seed/nocap/400/300' 
    },
    { 
      id: '2', 
      term: 'Delulu', 
      definition: 'Ảo tưởng sức mạnh, suy nghĩ viển vông về một cái gì đó.', 
      imageUrl: 'https://picsum.photos/seed/delulu/400/300' 
    },
    { 
      id: '3', 
      term: 'Ghosting', 
      definition: 'Tự dưng biến mất như một hồn ma mà không có lý do.', 
      imageUrl: 'https://picsum.photos/seed/ghost/400/300' 
    },
    { 
      id: '4', 
      term: 'Main Character Energy', 
      definition: 'Thần thái tự tin như nhân vật chính của một bộ phim.', 
      imageUrl: 'https://picsum.photos/seed/main/400/300' 
    }
  ];

  const handleNext = () => {
    setIsFlipped(false);
    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      setCompleted(true);
      addCoins(100);
    }
  };

  const handleFeedback = (correct: boolean) => {
    if (correct) addCoins(20);
    handleNext();
  };

  if (completed) {
    return (
      <div className="text-center py-20 space-y-6 animate-in zoom-in duration-500">
        <div className="w-32 h-32 bg-yellow-500 rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-yellow-500/30">
          <CheckCircle2 size={64} className="text-slate-900" />
        </div>
        <h2 className="text-4xl font-black">XUẤT SẮC! 🎉</h2>
        <p className="text-slate-400 text-xl max-w-md mx-auto">Bạn đã hoàn thành bộ thẻ "Tiếng Anh chém gió". Nhận ngay 100 Skibidi Coins!</p>
        <button 
          onClick={() => {setCompleted(false); setCurrentIndex(0);}}
          className="px-8 py-3 bg-orange-500 rounded-2xl font-bold hover:bg-orange-600 transition-colors"
        >
          Học lại bộ này
        </button>
      </div>
    );
