    {
      id: "2",
      word: "Slay",
      phonetic: "/sleɪ/",
      vietnamese: "Làm cực tốt / Đỉnh nóc kịch trần",
      example: "Your English skills are slaying!",
      meme_url: "https://picsum.photos/seed/slay/400/300"
    }
  ];

  const handleNext = () => {
    setIsFlipped(false);
    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      setCompleted(true);
      addCoins(100);
    }
  };

  const handleFeedback = (correct: boolean) => {
    if (correct) addCoins(20);
    handleNext();
  };

  if (completed) {
    return (
      <div className="text-center py-20 space-y-6 animate-in zoom-in duration-500">
        <div className="w-32 h-32 bg-yellow-500 rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-yellow-500/30">
          <CheckCircle2 size={64} className="text-slate-900" />
        </div>
        <h2 className="text-4xl font-black text-white">XUẤT SẮC! 🎉</h2>
        <p className="text-slate-400 text-xl max-w-md mx-auto">Bạn đã hoàn thành bộ thẻ chuẩn Skibidi. Nhận ngay 100 Skibidi Coins!</p>
        <button 
          onClick={() => {setCompleted(false); setCurrentIndex(0);}}
          className="px-8 py-3 bg-orange-500 rounded-2xl font-bold hover:bg-orange-600 transition-colors text-white"
        >
          Học lại bộ này
        </button>
      </div>
    );
  }

  const currentCard = cards[currentIndex];

  return (
    <div className="max-w-xl mx-auto space-y-12 animate-in fade-in slide-in-from-top duration-500">
      <div className="text-center">
        <h2 className="text-3xl font-black mb-2 uppercase tracking-tighter text-white">Memory Skibidi 🧠</h2>
        <p className="text-slate-400">Dễ nhớ hơn cả người yêu cũ.</p>
        <div className="mt-6 h-2 w-full bg-slate-800 rounded-full overflow-hidden">
          <div 
            className="h-full bg-[#FF00FF] transition-all duration-500" 
            style={{ width: `${((currentIndex + 1) / cards.length) * 100}%` }}
          ></div>
        </div>
        <p className="text-xs text-slate-500 mt-2 font-bold uppercase tracking-widest">Thẻ {currentIndex + 1} / {cards.length}</p>
      </div>

      <div 
        className="relative perspective-1000 w-full h-[300px] cursor-pointer group"
        onClick={() => setIsFlipped(!isFlipped)}
      >
        <div className={`
          relative w-full h-full transition-all duration-500 preserve-3d
          ${isFlipped ? 'rotate-y-180' : ''}
        `}>
          {/* Front - Neon Tím */}
          <div className="absolute inset-0 backface-hidden bg-[#FF00FF] p-8 rounded-[20px] flex flex-col items-center justify-center border-4 border-white/20 shadow-[0_0_30px_rgba(255,0,255,0.4)] transition-all">
            <h3 className="text-[48px] font-black text-center text-white uppercase tracking-tighter drop-shadow-lg">
              {currentCard.word}
            </h3>
            <p className="text-white/80 font-mono mt-2">{currentCard.phonetic}</p>
            <p className="mt-8 text-white/60 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
              <RotateCw size={14} /> Chạm để lật
            </p>
          </div>

          {/* Back - Neon Xanh */}
          <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#00FFFF] p-8 rounded-[20px] flex flex-col items-center justify-center border-4 border-white/20 shadow-[0_0_30px_rgba(0,255,255,0.4)] transition-all overflow-hidden">
             <div className="relative z-10 w-full flex flex-col items-center justify-center text-black">
               <h3 className="text-[32px] font-black text-center leading-tight mb-4">{currentCard.vietnamese}</h3>
               <p className="text-[16px] italic text-center text-black/70 px-4">"{currentCard.example}"</p>
             </div>
          </div>
        </div>
      </div>

      <div className="flex justify-center gap-6">
        <button 
          onClick={(e) => { e.stopPropagation(); handleFeedback(false); }}
          className="flex-1 max-w-[160px] py-4 rounded-2xl bg-slate-900 border border-red-500/20 text-red-500 font-bold hover:bg-red-500/10 flex items-center justify-center gap-2 transition-all"
        >
          <XCircle size={20} /> Chưa nhớ
        </button>
        <button 
          onClick={(e) => { e.stopPropagation(); handleFeedback(true); }}
          className="flex-1 max-w-[160px] py-4 rounded-2xl bg-slate-900 border border-green-500/20 text-green-500 font-bold hover:bg-green-500/10 flex items-center justify-center gap-2 transition-all"
        >
          <CheckCircle2 size={20} /> Đã nhớ
        </button>
      </div>

      <style>{`
        .perspective-1000 { perspective: 1000px; }
        .preserve-3d { transform-style: preserve-3d; }
        .backface-hidden { backface-visibility: hidden; }
        .rotate-y-180 { transform: rotateY(180deg); }
      `}</style>
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect } from 'react';
import { ViewType, UserStats } from './types';
import Dashboard from './components/Dashboard';
import Dictionary from './components/Dictionary';
import Flashcards from './components/Flashcards';
import SpeakingCoach from './components/SpeakingCoach';
import BattleArena from './components/BattleArena';
import PetStore from './components/PetStore';
import { 
  Home, 
  Book, 
  Layers, 
  Mic2, 
  Swords, 
  Ghost, 
  Coins, 
  Flame,
  Menu,
  X
} from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>(ViewType.DASHBOARD);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [stats, setStats] = useState<UserStats>({
    coins: 1250,
    streak: 7,
    level: 'Dân Chơi',
    xp: 450
  });

  const addCoins = (amount: number) => {
    setStats(prev => ({ ...prev, coins: prev.coins + amount }));
  };

  const renderView = () => {
    switch (currentView) {
      case ViewType.DASHBOARD: return <Dashboard stats={stats} setView={setCurrentView} />;
      case ViewType.DICTIONARY: return <Dictionary addCoins={addCoins} />;
      case ViewType.FLASHCARDS: return <Flashcards addCoins={addCoins} />;
      case ViewType.SPEAKING: return <SpeakingCoach addCoins={addCoins} />;
      case ViewType.BATTLE: return <BattleArena addCoins={addCoins} stats={stats} />;
      case ViewType.PET: return <PetStore stats={stats} setStats={setStats} />;
      default: return <Dashboard stats={stats} setView={setCurrentView} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <header className="md:hidden flex items-center justify-between p-4 skibidi-glass sticky top-0 z-50">
        <h1 className="text-2xl font-extrabold tracking-tighter text-orange-500">TÙNG SKIBIDI</h1>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2">
          {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </header>

      {/* Sidebar Navigation */}
      <nav className={`
        fixed inset-0 z-40 bg-slate-900 md:bg-transparent md:relative md:flex md:flex-col md:w-64 lg:w-72
        transform transition-transform duration-300 ease-in-out
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="flex flex-col h-full p-6 skibidi-glass m-4 rounded-3xl border-slate-800">
          <div className="hidden md:block mb-8">
            <h1 className="text-3xl font-extrabold tracking-tighter text-orange-500">TÙNG SKIBIDI</h1>
            <p className="text-slate-400 text-xs mt-1 font-semibold uppercase tracking-widest">Học Chuẩn Trend</p>
          </div>

          <div className="flex flex-col gap-2 flex-grow">
            <NavItem icon={<Home />} label="Trang chủ" active={currentView === ViewType.DASHBOARD} onClick={() => {setCurrentView(ViewType.DASHBOARD); setIsMenuOpen(false);}} />
            <NavItem icon={<Book />} label="Từ điển xịn" active={currentView === ViewType.DICTIONARY} onClick={() => {setCurrentView(ViewType.DICTIONARY); setIsMenuOpen(false);}} />
            <NavItem icon={<Layers />} label="Thẻ ghi nhớ" active={currentView === ViewType.FLASHCARDS} onClick={() => {setCurrentView(ViewType.FLASHCARDS); setIsMenuOpen(false);}} />
            <NavItem icon={<Mic2 />} label="Luyện nói AI" active={currentView === ViewType.SPEAKING} onClick={() => {setCurrentView(ViewType.SPEAKING); setIsMenuOpen(false);}} />
            <NavItem icon={<Swords />} label="Đấu trường" active={currentView === ViewType.BATTLE} onClick={() => {setCurrentView(ViewType.BATTLE); setIsMenuOpen(false);}} />
            <NavItem icon={<Ghost />} label="Nuôi thú" active={currentView === ViewType.PET} onClick={() => {setCurrentView(ViewType.PET); setIsMenuOpen(false);}} />
          </div>

          <div className="mt-auto space-y-4 pt-6 border-t border-slate-800">
            <div className="flex items-center gap-3 px-4">
              <div className="p-2 rounded-xl bg-orange-500/20 text-orange-500">
                <Flame size={20} />
              </div>
              <div>
                <p className="text-xs text-slate-400">Chuỗi ngày</p>
                <p className="font-bold">{stats.streak} ngày</p>
              </div>
            </div>
            <div className="flex items-center gap-3 px-4">
              <div className="p-2 rounded-xl bg-yellow-500/20 text-yellow-500">
                <Coins size={20} />
              </div>
              <div>
                <p className="text-xs text-slate-400">Skibidi Coins</p>
                <p className="font-bold">{stats.coins.toLocaleString()}</p>
              </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow p-4 md:p-8 overflow-y-auto">
        <div className="max-w-5xl mx-auto pb-20 md:pb-0">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`
      flex items-center gap-4 px-4 py-3 rounded-2xl transition-all duration-200
      ${active 
        ? 'skibidi-gradient text-white shadow-lg shadow-orange-500/20' 
        : 'hover:bg-slate-800 text-slate-400 hover:text-white'}
    `}
  >
    {/* Fixed: Cast icon to React.ReactElement<any> to allow specifying 'size' prop in React.cloneElement call for Lucide icons */}
    {React.cloneElement(icon as React.ReactElement<any>, { size: 22 })}
    <span className="font-bold">{label}</span>
  </button>
);

export default App;
